import{_ as e,o as t,c as i,Q as o}from"./chunks/framework.b67c47e6.js";const f=JSON.parse('{"title":"Setting Up Production Lines","description":"","frontmatter":{},"headers":[],"relativePath":"tutorials/production_lines/index.md","filePath":"tutorials/production_lines/index.md","lastUpdated":1775899883000}'),s={name:"tutorials/production_lines/index.md"},n=o('<h1 id="setting-up-production-lines" tabindex="-1">Setting Up Production Lines <a class="header-anchor" href="#setting-up-production-lines" aria-label="Permalink to &quot;Setting Up Production Lines&quot;">​</a></h1><p>This tutorial walks you through configuring your production lines, stations, checklists, and machines from scratch.</p><nav class="table-of-contents"><ul><li><a href="#prerequisites">Prerequisites</a></li><li><a href="#step-1-create-a-production-line">Step 1: Create a Production Line</a></li><li><a href="#step-2-add-stations">Step 2: Add Stations</a></li><li><a href="#step-3-configure-subsets-optional">Step 3: Configure Subsets (Optional)</a></li><li><a href="#step-4-add-checklist-items">Step 4: Add Checklist Items</a></li><li><a href="#step-5-set-up-machines-optional">Step 5: Set Up Machines (Optional)</a></li><li><a href="#step-6-test-your-configuration">Step 6: Test Your Configuration</a></li><li><a href="#next-steps">Next Steps</a></li></ul></nav><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>You must have <strong>manager</strong> or <strong>admin</strong> access to your company.</li><li>At least one project should be set up to test the configuration.</li></ul><h2 id="step-1-create-a-production-line" tabindex="-1">Step 1: Create a Production Line <a class="header-anchor" href="#step-1-create-a-production-line" aria-label="Permalink to &quot;Step 1: Create a Production Line&quot;">​</a></h2><ol><li>Go to <strong>Company Settings &gt; Production Lines</strong>.</li><li>Click <strong>Add Production Line</strong>.</li><li>Fill in the form: <ul><li><strong>Name</strong> — A descriptive name for the line (e.g., &quot;Wall Panel Line 1&quot;).</li><li><strong>Type</strong> — Select which constructible categories this line produces (assemblies and/or modules).</li><li><strong>Client IDs</strong> — Optional. Add one or more external identifiers if this line needs to be matched from an external system (e.g. ERP). You can add multiple IDs if the line is referenced by more than one system.</li></ul></li><li>Save the production line.</li></ol><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Every company needs at least one production line. You can create multiple lines for different product types or parallel manufacturing.</p></div><h2 id="step-2-add-stations" tabindex="-1">Step 2: Add Stations <a class="header-anchor" href="#step-2-add-stations" aria-label="Permalink to &quot;Step 2: Add Stations&quot;">​</a></h2><p>Stations represent the sequential steps in your production process.</p><ol><li>In the production line you just created, click <strong>Add Station</strong>.</li><li>Configure the station: <ul><li><strong>Name</strong> — E.g., &quot;Framing&quot;, &quot;Cladding&quot;, &quot;Quality Check&quot;.</li><li><strong>Client ID</strong> — Optional external identifier if integrating with other systems.</li><li><strong>Zones</strong> — Which zones this station handles (e.g., zone 0 for a typical framing station).</li><li><strong>Machine</strong> — If this is a machine station (e.g., Mobi One), link the machine setup here.</li></ul></li><li>Repeat for each station in your production process.</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Order your stations in the sequence they&#39;ll be performed. Production workers will see checklists in this order in the <a href="/guide/viewer/">Viewer</a>.</p></div><h2 id="step-3-configure-subsets-optional" tabindex="-1">Step 3: Configure Subsets (Optional) <a class="header-anchor" href="#step-3-configure-subsets-optional" aria-label="Permalink to &quot;Step 3: Configure Subsets (Optional)&quot;">​</a></h2><p>If you produce different types of panels (e.g., walls vs. roofs) that require different station configurations:</p><ol><li>Define subsets on your production line.</li><li>For each station, set <strong>Disabled Subsets</strong> to hide that station for specific subsets.</li><li>When creating batches, assign the appropriate subset.</li></ol><div class="info custom-block"><p class="custom-block-title">INFO</p><p>For more details on subsets, see the <a href="/guide/management/production_lines/">Production Lines reference</a>.</p></div><h2 id="step-4-add-checklist-items" tabindex="-1">Step 4: Add Checklist Items <a class="header-anchor" href="#step-4-add-checklist-items" aria-label="Permalink to &quot;Step 4: Add Checklist Items&quot;">​</a></h2><p>Each station can have checklist tasks that production workers must complete.</p><ol><li>In a station, click <strong>Add Checklist Item</strong>.</li><li>Configure: <ul><li><strong>Task text</strong> — The instruction shown to the worker (e.g., &quot;Check frame alignment&quot;).</li><li><strong>DOCS</strong> — Optional documentation for the task (guidelines, specifications).</li><li><strong>Branches</strong> — Limit this task to constructibles containing specific branches (leave empty for all).</li><li><strong>Subsets</strong> — Limit to specific subsets (leave empty for all).</li><li><strong>Inclusion criteria</strong> — Choose when this task appears: <ul><li><strong>All</strong> — Every constructible gets this task.</li><li><strong>1/n</strong> — Added once every n constructibles (for periodic quality checks).</li><li><strong>1/n randomized</strong> — Same as 1/n but at random intervals.</li></ul></li></ul></li><li>Repeat for all tasks at this station.</li></ol><h2 id="step-5-set-up-machines-optional" tabindex="-1">Step 5: Set Up Machines (Optional) <a class="header-anchor" href="#step-5-set-up-machines-optional" aria-label="Permalink to &quot;Step 5: Set Up Machines (Optional)&quot;">​</a></h2><p>If any station uses automated equipment (e.g., a Mobi One):</p><ol><li>Go to the <strong>Machines</strong> section in Production Lines settings.</li><li>Create a new machine with the appropriate model type.</li><li>Configure the machine settings (see <a href="/guide/machine_files/machines/mobi_one/">Mobi One</a> for an example).</li><li>Link the machine to the corresponding station.</li></ol><h2 id="step-6-test-your-configuration" tabindex="-1">Step 6: Test Your Configuration <a class="header-anchor" href="#step-6-test-your-configuration" aria-label="Permalink to &quot;Step 6: Test Your Configuration&quot;">​</a></h2><ol><li>Open a project that has designs and constructibles.</li><li>Start production on a constructible in the <a href="/guide/viewer/">Viewer</a>.</li><li>Verify that: <ul><li>The correct stations appear in order.</li><li>Checklist tasks are shown for each station.</li><li>Machine files can be generated (if applicable).</li></ul></li></ol><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="/tutorials/projects/">Build a Project</a> — Upload files and generate designs.</li><li><a href="/tutorials/ifcps/">IFC Parsing Setup</a> — Configure how IFC files are interpreted.</li><li><a href="/guide/planning/">Production Planning</a> — Schedule constructibles on the calendar.</li></ul>',26),a=[n];function r(l,c,u,p,d,h){return t(),i("div",null,a)}const m=e(s,[["render",r]]);export{f as __pageData,m as default};
